Here's a complete example with both `DataRow` and `DynamicData` approaches:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // --- DataRow: inline constant values ---

    [TestMethod]
    [DataRow(1, 10.00, 10.00)]
    [DataRow(5, 3.50, 17.50)]
    [DataRow(0, 99.99, 0.00)]
    [DataRow(100, 0.01, 1.00)]
    public void CalculateTotal_ReturnsExpected(int quantity, double unitPrice, double expected)
    {
        var result = _calculator.CalculateTotal(quantity, (decimal)unitPrice);
        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(100.00, 0.10, 90.00)]   // 10% off
    [DataRow(200.00, 0.25, 150.00)]  // 25% off
    [DataRow(50.00, 0.00, 50.00)]    // no discount
    [DataRow(80.00, 1.00, 0.00)]     // 100% off
    public void ApplyDiscount_ReturnsExpected(double price, double discount, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discount);
        Assert.AreEqual((decimal)expected, result);
    }

    // --- DynamicData: complex/non-constant scenarios ---

    [TestMethod]
    [DynamicData(nameof(BulkOrderCases), DynamicDataSourceType.Method)]
    public void CalculateTotal_BulkOrders_ReturnsExpected(
        int quantity, decimal unitPrice, decimal expected)
    {
        var result = _calculator.CalculateTotal(quantity, unitPrice);
        Assert.AreEqual(expected, result);
    }

    private static IEnumerable<object[]> BulkOrderCases()
    {
        yield return new object[] { 1000, 1.99m, 1990.00m };
        yield return new object[] { 500, 49.99m, 24995.00m };
        yield return new object[] { 10, 0.001m, 0.01m };
    }

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountCases), DynamicDataSourceType.Property)]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void ApplyDiscount_InvalidRate_Throws(decimal price, decimal discount)
    {
        _calculator.ApplyDiscount(price, discount);
    }

    public static IEnumerable<object[]> InvalidDiscountCases => new[]
    {
        new object[] { 100m, -0.1m },   // negative
        new object[] { 100m, 1.5m },    // over 100%
    };
}
```

**Key points:**

- **`[DataRow]`** — best for simple, inline constant values (no `decimal` literals allowed, use `double` and cast).
- **`[DynamicData]`** — use when you need `decimal`, complex objects, or computed test data. Can point to a `Method` or `Property`.
- **`[TestInitialize]`** — avoids repeated setup in each test.
- **`[ExpectedException]`** — validates error paths. Alternatively, use `Assert.ThrowsException<T>()` for inline assertion.

If you're on **MSTest v3+**, you can also use `[DynamicData]` with `DynamicDataDisplayName` for readable test names in the explorer:

```csharp
[DynamicData(nameof(BulkOrderCases), DynamicDataSourceType.Method,
    DynamicDataDisplayName = nameof(GetDisplayName))]
```

